  name: string;
  type: 'Anthro' | 'Human';
  description: string;
  baseObject?: string;
  appliedVoice: string;
}

export interface VideoScene {
  id: number;
  speaker: string;
  listener: string;
  dialogue: string;
  emotion: string;
  visualAction: string;
  soundEnvironment: string;
  technicalPrompt: string;
  illustrationUrl?: string;
