import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";
import { CharacterInfo, VideoScene, AnthroProject } from "../types";

const cleanJsonResponse = (text: string) => text.replace(/```json|```/g, "").trim();

export const analyzeAndSplitScript = async (script: string): Promise<AnthroProject> => {
  const ai = getAiClient();
  const prompt = `
    Bạn là một đạo diễn hoạt hình chuyên nghiệp. Hãy phân tích kịch bản sau để tạo video nhân hóa (con vật/đồ vật biết nói).
    Kịch bản: "${script}"

    NHIỆM VỤ:
    1. Xác định bối cảnh chính (Main Setting).
    2. Xác định danh sách nhân vật: Tên, Loại (Nhân hóa/Người), Mô tả hình dáng (Nếu nhân hóa: chỉ thêm mắt miệng hoạt hình, giữ nguyên form gốc của vật thể).
    3. Tông cảm xúc chung (phóng đại tối đa).
    4. Chia kịch bản thành các cảnh (Scenes) logic:
       - Mỗi cảnh 7-8 giây (khoảng 130-180 ký tự).
       - Xác định rõ Người nói (Speaker) và Người nghe (Listener).
       - Cảm xúc cảnh đó (phải cực kỳ mạnh mẽ: 8-10/10).
       - Hành động minh họa lời thoại.
       - Âm thanh môi trường đặc trưng (clink, splash, hiss...).

    YÊU CẦU ĐỘC QUYỀN:
    - KHÔNG tự bịa nội dung ngoài kịch bản.
    - Lời thoại giữ nguyên 100%.

    Trả về JSON theo cấu trúc AnthroProject.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts: [{ text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          overallTone: { type: Type.STRING },
          mainSetting: { type: Type.STRING },
          characters: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                type: { type: Type.STRING, enum: ["Anthro", "Human"] },
                description: { type: Type.STRING },
                baseObject: { type: Type.STRING },
                appliedVoice: { type: Type.STRING }
              },
              required: ["name", "type", "description"]
            }
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                speaker: { type: Type.STRING },
                listener: { type: Type.STRING },
                dialogue: { type: Type.STRING },
                emotion: { type: Type.STRING },
                visualAction: { type: Type.STRING },
                soundEnvironment: { type: Type.STRING }
              },
              required: ["id", "speaker", "listener", "dialogue", "emotion", "visualAction", "soundEnvironment"]
            }
          }
        },
        required: ["overallTone", "mainSetting", "characters", "scenes"]
      }
    }
  });

  const data = JSON.parse(cleanJsonResponse(response.text || "{}"));
  return { ...data, originalScript: script };
};

export const generateTechnicalPrompt = async (
  scene: VideoScene, 
  project: AnthroProject
): Promise<string> => {
  const ai = getAiClient();
  const char = project.characters.find(c => c.name === scene.speaker);

  const instruction = `
    Nhiệm vụ: Viết Technical Video Prompt (English) cho VEO-3 dài 8 giây.

    PHONG CÁCH: Điện ảnh, Phóng đại cảm xúc (8-10/10), Hoạt hình hóa thực tế.

    CẤU TRÚC BẮT BUỘC (VIẾT TRÊN 1 DÒNG):
    1. SUBJECT & LOOK: ${scene.speaker} (${char?.type}). ${char?.description}. Nếu là Anthro: GIỮ NGUYÊN HÌNH DẠNG VẬT THỂ, chỉ thêm mắt và miệng hoạt hình biểu cảm. TUYỆT ĐỐI KHÔNG GHÉP MẶT NGƯỜI.
    2. INTERACTION: Đang nói chuyện với ${scene.listener}. Không nhìn vào camera. Ánh mắt hướng về đối phương.
    3. AMPLIFIED EMOTION: Cảm xúc "${scene.emotion}". Biểu hiện: mô tả chi tiết phóng đại (ví dụ: bốc khói, mặt đỏ rực, mắt trợn trừng, vai run bần bật).
    4. ACTION: ${scene.visualAction}. Chuyển động môi khớp hoàn hảo lời thoại.
    5. SETTING & LIGHTING: ${project.mainSetting}. Ánh sáng kịch tính làm nổi bật cảm xúc.
    6. SOUNDSCAPE: Âm thanh cực rõ: ${scene.soundEnvironment}.
    7. DIALOGUE: ✨ Character speaks: "${scene.dialogue}"
    8. TECHNICAL: 9:16, 4K, 60fps, cinematic, masterpiece.

    YÊU CẦU: Trả về duy nhất 1 dòng Tiếng Anh (trừ lời thoại).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [{ text: instruction }] }
  });

  return response.text?.trim() || "";
};

export const generateIllustration = async (
  scene: VideoScene, 
  project: AnthroProject,
  refImage?: string
): Promise<string> => {
  const ai = getAiClient();
  const char = project.characters.find(c => c.name === scene.speaker);

  const prompt = `
    Photorealistic high-end 3D Render (Pixar/Disney Style). 9:16 aspect ratio.
    SUBJECT: ${scene.speaker}. ${char?.description}. 
    EMOTION: ${scene.emotion} (AMPLIFIED 10/10 intensity). Visual cues: bulging veins, cartoonish steam, intense facial expression.
    SETTING: ${project.mainSetting}.
    NO TEXT, NO UI, NO SUBTITLES. 
    ${refImage ? "Maintain exact consistency with the character appearance in the provided reference image." : ""}
  `;

  const parts: any[] = [{ text: prompt }];
  if (refImage) {
    parts.push({ inlineData: { mimeType: "image/png", data: refImage.split(",")[1] } });
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: { parts },
    config: { imageConfig: { aspectRatio: "9:16" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
};

