      return {
        ...prev,
        scenes: prev.scenes.map(s => s.id === sceneId ? { ...s, isLoadingPrompt: true } : s)
      };
    });

    try {
      const scene = project.scenes.find(s => s.id === sceneId)!;
      const prompt = await service.generateTechnicalPrompt(scene, project);
      setProject(prev => {
