          className="w-full h-48 p-6 bg-slate-50 border-2 border-slate-100 rounded-3xl focus:ring-4 focus:ring-orange-50 focus:border-orange-500 outline-none transition-all text-sm font-medium leading-relaxed resize-none shadow-inner"
        />

        <div className="mt-6 flex gap-4">
