import React, { useState } from 'react';
import AnthroVideoModule from './modules/AnthroVideoModule';
import ErrorBoundary from './components/ErrorBoundary';
import { VALID_USERS } from './types';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('koc_studio_auth') === 'true';
  });
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = VALID_USERS.find(u => u.u === username && u.p === password);
    if (user) {
      setIsAuthenticated(true);
      sessionStorage.setItem('koc_studio_auth', 'true');
    } else {
      alert('Sai tài khoản hoặc mật khẩu!');
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl border border-slate-200">
          <div className="flex flex-col items-center mb-10">
            <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">ANTHRO <span className="text-orange-600">STUDIO</span></h1>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.3em] mt-1">Video Prompt Engine</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Username" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold outline-none focus:border-orange-500" required />
            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold outline-none focus:border-orange-500" required />
            <button type="submit" className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:bg-orange-700 transition-all uppercase tracking-widest mt-4">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <ErrorBoundary>
      <div className="min-h-screen bg-slate-50 font-['Inter'] pb-20">
        <nav className="bg-white border-b border-slate-100 h-20 flex items-center shadow-sm sticky top-0 z-50">
          <div className="max-w-7xl mx-auto w-full px-6 flex justify-between items-center">
            <div className="flex flex-col leading-none">
              <span className="text-slate-800 font-black text-xl tracking-tighter uppercase">ANTHRO <span className="text-orange-600">STUDIO</span></span>
              <span className="text-slate-400 font-bold text-[8px] tracking-[0.2em] uppercase mt-0.5">Creative AI Engine</span>
            </div>
            <button onClick={() => { sessionStorage.removeItem('koc_studio_auth'); window.location.reload(); }} className="text-[10px] font-black text-slate-400 hover:text-red-600 uppercase tracking-widest transition-colors">Logout</button>
          </div>
        </nav>
        <main>
          <AnthroVideoModule />
        </main>
        <footer className="fixed bottom-0 left-0 right-0 h-12 bg-white border-t border-slate-200 flex items-center justify-center z-40">
           <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">© 2025 Anthro Prompt Generator - AI Studio Edition</span>
        </footer>
      </div>
    </ErrorBoundary>
  );
};

export default App;

