                  <ImageCard 
                    label={`Cảnh ${idx+1}`} 
                    imageData={imageData} 
                    videoPrompt={promptData} 
                    onRegenerate={() => handleGenImage(key)} 
                    onGeneratePrompt={() => handleGenVideoPrompt(key)} 
                    onTranslate={() => {}} 
                    onDelete={() => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], url: '', loading: false } } }))}
                    pose={imageData.pose} 
                    onPoseChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: val } } }))} 
                    angle={imageData.angle} 
                    onAngleChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], angle: val } } }))} 
                    shot={imageData.shot}
                    onShotChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], shot: val } } }))}
                    speaker={speakerTalking}
                    onSpeakerChange={(val) => setState(p => ({ ...p, sceneSpeakers: { ...p.sceneSpeakers, [key]: val } }))}
