import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";
import { CharacterInfo, VideoScene, AnthroProject } from "../types";

const cleanJsonResponse = (text: string) => text.replace(/```json|```/g, "").trim();

export const analyzeAndSplitScript = async (script: string): Promise<AnthroProject> => {
  const ai = getAiClient();
  const prompt = `
    Bạn là một đạo diễn hoạt hình chuyên nghiệp. Hãy phân tích kịch bản sau để tạo video nhân hóa (con vật/đồ vật biết nói).
    Kịch bản: "${script}"

    NHIỆM VỤ:
    1. Xác định bối cảnh chính (Main Setting).
    2. Xác định danh sách nhân vật: Tên, Loại (Nhân hóa/Người), Mô tả hình dáng (Nếu nhân hóa: chỉ thêm mắt miệng hoạt hình, giữ nguyên form gốc của vật thể).
    3. Tông cảm xúc chung (phóng đại tối đa 8-10/10).
    4. Chia kịch bản thành các cảnh (Scenes) logic:
       - Mỗi cảnh 7-8 giây (khoảng 130-180 ký tự).
       - Xác định rõ Người nói (Speaker) và Người nghe (Listener - đối tượng đang bị nói tới).
       - Cảm xúc cảnh đó (phải cực kỳ mạnh mẽ: 8-10/10).
       - Hành động minh họa lời thoại.
       - Âm thanh môi trường đặc trưng (clink, splash, hiss...).

    YÊU CẦU ĐỘC QUYỀN:
    - KHÔNG tự bịa nội dung ngoài kịch bản.
    - Lời thoại giữ nguyên 100%.

    Trả về JSON theo cấu trúc AnthroProject.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts: [{ text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          overallTone: { type: Type.STRING },
          mainSetting: { type: Type.STRING },
          characters: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                type: { type: Type.STRING, enum: ["Anthro", "Human"] },
                description: { type: Type.STRING },
                baseObject: { type: Type.STRING },
                appliedVoice: { type: Type.STRING }
              },
              required: ["name", "type", "description"]
            }
          },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                speaker: { type: Type.STRING },
                listener: { type: Type.STRING },
                dialogue: { type: Type.STRING },
                emotion: { type: Type.STRING },
                visualAction: { type: Type.STRING },
                soundEnvironment: { type: Type.STRING }
              },
              required: ["id", "speaker", "listener", "dialogue", "emotion", "visualAction", "soundEnvironment"]
            }
          }
        },
        required: ["overallTone", "mainSetting", "characters", "scenes"]
      }
    }
  });

  const data = JSON.parse(cleanJsonResponse(response.text || "{}"));
  return { ...data, originalScript: script };
};

export const generateTechnicalPrompt = async (
  scene: VideoScene, 
  project: AnthroProject
): Promise<string> => {
  const ai = getAiClient();
  const char = project.characters.find(c => c.name === scene.speaker);

  const cognitiveAddon = `
    "This update is additive-only. It must not modify, rewrite, simplify, or override any existing prompt generation logic. 
    Its sole purpose is to clarify who the speaking character is addressing, only when that information is missing."

    CRITICAL COGNITIVE RULE:
    - SPEAKER: ${scene.speaker} (The character speaking).
    - LISTENER: ${scene.listener} (The target being addressed).
    - If dialogue is nagging/scolding/ordering: The character MUST focus its gaze and gestures towards ${scene.listener}.
    - ABSOLUTELY NO speaking to the camera or addressing the viewer.
    - If the listener is ${scene.listener}, include "a visible listener reacting in frame" or "addressing the person present" to clarify the relationship.
  `;

  const instruction = `
    Nhiệm vụ: Viết Technical Video Prompt (English) cho VEO-3 dài 8 giây.

    PHONG CÁCH: Điện ảnh, Phóng đại cảm xúc (8-10/10), Hoạt hình hóa thực tế.

    ${cognitiveAddon}

    CẤU TRÚC BẮT BUỘC (VIẾT TRÊN 1 DÒNG):
    1. SUBJECT & LOOK: ${scene.speaker} (${char?.type}). ${char?.description}. Nếu là Anthro: GIỮ NGUYÊN HÌNH DẠNG VẬT THỂ, chỉ thêm mắt và miệng hoạt hình biểu cảm. TUYỆT ĐỐI KHÔNG GHÉP MẶT NGƯỜI.
    2. INTERACTION: Đang nói chuyện trực tiếp với ${scene.listener}. Ánh mắt hướng về đối phương, không nhìn vào ống kính máy ảnh. 
    3. AMPLIFIED EMOTION: Cảm xúc "${scene.emotion}". Biểu hiện: mô tả chi tiết phóng đại (ví dụ: bốc khói từ tai, mặt đỏ rực, mắt trợn trừng, vai run bần bật vì tức giận).
    4. ACTION: ${scene.visualAction}. Chuyển động môi (lip-sync) khớp hoàn hảo lời thoại.
    5. SETTING & LIGHTING: ${project.mainSetting}. Ánh sáng kịch tính làm nổi bật cảm xúc nhân vật.
    6. SOUNDSCAPE: Âm thanh môi trường: ${scene.soundEnvironment}.
    7. DIALOGUE: ✨ Character speaks: "${scene.dialogue}"
    8. TECHNICAL: 9:16, 4K, 60fps, cinematic, masterpiece.

    YÊU CẦU: Trả về duy nhất 1 dòng Tiếng Anh (trừ lời thoại).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [{ text: instruction }] }
  });

  return response.text?.trim() || "";
};

export const generateIllustration = async (
  scene: VideoScene, 
  project: AnthroProject,
  refImage?: string
): Promise<string> => {
  const ai = getAiClient();
  const char = project.characters.find(c => c.name === scene.speaker);

  const characterFidelityLaw = `
    "Image generation must strictly follow the prompt: number of characters, emotions, actions, and interactions must match exactly. Do not omit any character mentioned in the prompt."

    LAWS:
    1. PROMPT CONTAINS 2 CHARACTERS: ${scene.speaker} (Speaking) and ${scene.listener} (Listening).
    2. YOU MUST DRAW BOTH: Both characters MUST be visible in the frame.
    3. DIALOGUE CONTEXT: This is a conversation. Show the interaction. The speaker should be addressing the listener directly.
    4. NO CAMERA EYE CONTACT: Characters must NOT look at the viewer.
  `;

  const prompt = `
    Photorealistic high-end 3D Render (Pixar/Disney Style). 9:16 aspect ratio.
    ${characterFidelityLaw}
    SUBJECTS: ${scene.speaker} (${char?.description}) interacting with ${scene.listener}.
    EMOTION: ${scene.emotion} (AMPLIFIED 10/10 intensity). Visual cues: bulging veins, cartoonish steam, intense facial expression directed at the ${scene.listener} who is visible in frame reacting.
    SETTING: ${project.mainSetting}.
    NO TEXT, NO UI, NO SUBTITLES. 
    ${refImage ? "Maintain exact consistency with the character appearance in the provided reference image." : ""}
  `;

  const parts: any[] = [{ text: prompt }];
  if (refImage) {
    parts.push({ inlineData: { mimeType: "image/png", data: refImage.split(",")[1] } });
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: { parts },
    config: { imageConfig: { aspectRatio: "9:16" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/anthroService';
import { AnthroProject, VideoScene } from '../types';

declare var JSZip: any;

const AnthroVideoModule: React.FC = () => {
  const [script, setScript] = useState('');
  const [project, setProject] = useState<AnthroProject | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const scenesEndRef = useRef<HTMLDivElement>(null);

  const handleProcessScript = async () => {
    if (!script.trim()) return;
    setIsLoading(true);
    try {
      const result = await service.analyzeAndSplitScript(script);
      setProject(result);
    } catch (e) {
      alert("Lỗi phân tích kịch bản. Vui lòng thử lại.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenPrompt = async (sceneId: number) => {
    if (!project) return;
    setProject(prev => {
      if (!prev) return null;
      return {
        ...prev,
        scenes: prev.scenes.map(s => s.id === sceneId ? { ...s, isLoadingPrompt: true } : s)
      };
    });

    try {
      const scene = project.scenes.find(s => s.id === sceneId)!;
      const prompt = await service.generateTechnicalPrompt(scene, project);
      setProject(prev => {
        if (!prev) return null;
        return {
          ...prev,
          scenes: prev.scenes.map(s => s.id === sceneId ? { ...s, technicalPrompt: prompt, isLoadingPrompt: false } : s)
        };
      });
    } catch (e) {
      setProject(prev => {
        if (!prev) return null;
        return {
          ...prev,
          scenes: prev.scenes.map(s => s.id === sceneId ? { ...s, isLoadingPrompt: false } : s)
        };
      });
    }
  };

  const handleGenImage = async (sceneId: number) => {
    if (!project) return;
    setProject(prev => {
      if (!prev) return null;
      return {
        ...prev,
        scenes: prev.scenes.map(s => s.id === sceneId ? { ...s, isLoadingImage: true } : s)
      };
    });

    try {
      const scene = project.scenes.find(s => s.id === sceneId)!;
      // Use the first scene image of the same character as reference if available
      const charRef = project.scenes.find(s => s.speaker === scene.speaker && s.illustrationUrl)?.illustrationUrl;

      const url = await service.generateIllustration(scene, project, charRef);
      setProject(prev => {
        if (!prev) return null;
        return {
          ...prev,
          scenes: prev.scenes.map(s => s.id === sceneId ? { ...s, illustrationUrl: url, isLoadingImage: false } : s)
        };
      });
    } catch (e) {
      setProject(prev => {
        if (!prev) return null;
        return {
          ...prev,
          scenes: prev.scenes.map(s => s.id === sceneId ? { ...s, isLoadingImage: false } : s)
        };
      });
    }
  };

  const handleGenAll = async () => {
    if (!project) return;
    for (const s of project.scenes) {
      if (!s.technicalPrompt) await handleGenPrompt(s.id);
      if (!s.illustrationUrl) await handleGenImage(s.id);
    }
  };

  const handleDownloadPrompts = () => {
    if (!project) return;
    const text = project.scenes
      .map(s => `SCENE ${s.id} [${s.speaker}]:\n${s.technicalPrompt || "Not generated"}`)
      .join("\n\n---\n\n");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Prompts_${Date.now()}.txt`;
    link.click();
  };

  const handleDownloadAllImages = async () => {
    if (!project || typeof JSZip === 'undefined') return;
    const zip = new JSZip();
    let count = 0;
    project.scenes.forEach((s, i) => {
      if (s.illustrationUrl) {
        const base64Data = s.illustrationUrl.split(",")[1];
        if (base64Data) {
          zip.file(`Scene_${String(s.id).padStart(2, '0')}.png`, base64Data, { base64: true });
          count++;
        }
      }
    });

    if (count === 0) {
      alert("Chưa có ảnh nào để tải.");
      return;
    }

    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `Visuals_${Date.now()}.zip`;
    link.click();
  };

  return (
    <div className="max-w-6xl mx-auto px-6 py-10">
      {/* Script Input Section */}
      <div className="bg-white rounded-[2rem] shadow-xl border border-slate-200 p-8 mb-10 transition-all hover:shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Anthro <span className="text-orange-600">Video Engine</span></h1>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Phóng đại cảm xúc & Nhân hóa tuyệt đối</p>
          </div>
          {isLoading && (
            <div className="flex items-center gap-3 bg-orange-50 px-4 py-2 rounded-full border border-orange-100">
              <div className="w-4 h-4 border-2 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
              <span className="text-[10px] font-black text-orange-600 uppercase">Đang phân tích kịch bản...</span>
            </div>
          )}
        </div>

        <textarea
          value={script}
          onChange={(e) => setScript(e.target.value)}
          placeholder="Dán kịch bản của bạn vào đây (Ví dụ: Một quả thận đang than vãn với chủ nhân vì uống ít nước...)"
          className="w-full h-48 p-6 bg-slate-50 border-2 border-slate-100 rounded-3xl focus:ring-4 focus:ring-orange-50 focus:border-orange-500 outline-none transition-all text-sm font-medium leading-relaxed resize-none shadow-inner"
        />

        <div className="mt-6 flex gap-4">
          <button
            onClick={handleProcessScript}
            disabled={isLoading || !script.trim()}
            className="flex-1 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:bg-black transition-all active:scale-95 uppercase tracking-widest disabled:opacity-30"
          >
            Bắt đầu tạo Lộ trình
