              <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-black text-orange-500 uppercase tracking-widest">Tông cảm xúc chủ đạo</label>
                  <p className="text-2xl font-black uppercase tracking-tight mt-1">{project.overallTone}</p>
                </div>
                <div>
                  <label className="text-[10px] font-black text-orange-500 uppercase tracking-widest">Bối cảnh chính</label>
                  <p className="text-lg font-bold opacity-80">{project.mainSetting}</p>
                </div>
              </div>
              <div className="space-y-4">
                <label className="text-[10px] font-black text-orange-500 uppercase tracking-widest">Nhân vật đã xác định ({project.characters.length})</label>
                <div className="flex flex-wrap gap-2">
                  {project.characters.map((c, i) => (
                    <div key={i} className="bg-white/10 px-4 py-2 rounded-xl border border-white/10 group hover:bg-white/20 transition-all cursor-help relative">
                      <span className="text-[10px] font-black uppercase text-white">{c.name}</span>
                      <div className="hidden group-hover:block absolute bg-slate-800 p-3 rounded-xl border border-slate-700 shadow-2xl z-50 text-[10px] w-48 mt-2 left-0 top-full">
