              <button onClick={handleDownloadAllImages} className="px-10 py-4 bg-white text-slate-900 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-slate-200 active:scale-95 transition-all">Tải toàn bộ ảnh</button>
              <button onClick={handleDownloadPrompts} className="px-10 py-4 bg-slate-700 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-slate-800 active:scale-95 transition-all">Tải File Prompt (.TXT)</button>
