          {/* Scenes List */}
          <div className="space-y-8">
            {project.scenes.map((scene) => (
              <div key={scene.id} className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-stretch">
                {/* Meta & Dialogue Column */}
                <div className="lg:col-span-5 flex flex-col gap-6">
                  <div className="bg-white rounded-[2rem] border border-slate-200 p-8 shadow-sm h-full relative overflow-hidden group hover:shadow-lg transition-all">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-slate-50 rounded-bl-[4rem] -mr-10 -mt-10 transition-transform group-hover:scale-110"></div>

                    <div className="relative z-10">
                      <div className="flex justify-between items-center mb-6">
                        <span className="bg-slate-100 px-4 py-1.5 rounded-full text-[10px] font-black text-slate-500 uppercase tracking-widest">Cảnh {scene.id}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] font-black text-orange-600 uppercase">{scene.speaker}</span>
