                          <span className="text-[10px] font-black text-slate-400 uppercase">{scene.listener}</span>
                        </div>
                      </div>

                      <div className="mb-6">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] block mb-2 px-1">Cảm xúc khuếch đại</label>
                        <div className="bg-red-50 text-red-600 px-4 py-2 rounded-xl border border-red-100 font-black text-xs uppercase tracking-tight">
                          {scene.emotion} (8-10/10)
                        </div>
                      </div>

                      <div className="mb-6">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] block mb-2 px-1">Lời thoại (Kịch bản)</label>
                        <p className="text-sm font-bold text-slate-800 leading-relaxed bg-slate-50 p-4 rounded-2xl border border-slate-100 shadow-inner">
                          "{scene.dialogue}"
