                <div className="p-6 space-y-4 flex flex-col flex-1">
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-orange-600 uppercase">Lời thoại {seg.id}:</label>
                    <textarea value={seg.content} onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))} className="w-full h-24 p-3 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white resize-none" />
                  </div>

                  <div className="space-y-3">
                    <div className="space-y-1">
                        <label className="text-[9px] font-black text-blue-600 uppercase px-1">{isPersonified ? "Mô tả vật thể:" : "Vật thể bị ẩn"}</label>
                        <textarea 
                        value={seg.characterIdea} 
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, characterIdea: e.target.value } : s))} 
                        disabled={!isPersonified}
                        placeholder={isPersonified ? "Miếng sườn có tay chân..." : "Không có vật thể..."} 
                        className={`w-full h-16 p-3 border rounded-2xl text-[11px] font-medium outline-none focus:bg-white resize-none ${isPersonified ? 'bg-blue-50/50 border-blue-100' : 'bg-slate-100 border-slate-200 opacity-50'}`} 
                        />
                    </div>

                    <div className="space-y-1">
                        <label className="text-[9px] font-black text-emerald-600 uppercase px-1">Ai đang nói?</label>
                        <select 
                            value={seg.speaker} 
                            onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, speaker: e.target.value } : s))}
                            className="w-full p-2.5 bg-emerald-50 border border-emerald-100 rounded-xl text-[10px] font-black outline-none uppercase text-emerald-700"
                        >
                            <option value="Object">Vật thể nhân hóa</option>
                            {analyzedCharacters.map((char, idx) => (
                              <option key={`${char.name}-${idx}`} value={char.name}>{char.name}</option>
                            ))}
                        </select>
                    </div>
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                    <button onClick={() => handleGenImage(seg.id)} disabled={seg.image.loading} className="py-3 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase hover:bg-black transition-all">Vẽ ảnh</button>
                    <button onClick={() => handleGenPrompt(seg.id)} disabled={seg.videoPrompt.loading} className="py-3 bg-orange-100 text-orange-700 text-[10px] font-black rounded-xl uppercase border border-orange-200">Prompt</button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-4 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-2"><span className="text-[8px] font-black text-emerald-500 uppercase">Prompt Ready</span><button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[8px] text-white underline font-black uppercase">Copy</button></div>
                    {seg.videoPrompt.loading ? <div className="h-8 flex items-center justify-center"><div className="w-4 h-4 border-2 border-emerald-500 border-t-white rounded-full animate-spin"></div></div> : <p className="text-[9px] text-slate-400 italic leading-snug">"{seg.videoPrompt.text}"</p>}
                  </div>
                )}
              </div>
            ))}
          </div>

          <div className="flex flex-col gap-10 py-12 border-t border-slate-200">
            <div className="flex flex-col md:flex-row items-center justify-center gap-4">
               <button onClick={() => localJsonRef.current?.click()} className="w-full md:w-auto px-10 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl border border-slate-200 hover:bg-slate-200 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-sm">Tải Dự Án (JSON)</button>
               <input type="file" ref={localJsonRef} onChange={e => { const file = e.target.files?.[0]; if (file) { const reader = new FileReader(); reader.onload = (event) => processImportData(JSON.parse(event.target?.result as string)); reader.readAsText(file); } e.target.value = ""; }} className="hidden" accept="application/json" />
               <button onClick={handleLocalExportJson} className="w-full md:w-auto px-10 py-4 bg-indigo-600 text-white font-black rounded-2xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-lg">Lưu Dự Án (JSON)</button>
            </div>
            <div className="flex flex-col md:flex-row items-center justify-center gap-6">
                <button onClick={async () => { 
                    if (typeof JSZip === 'undefined') return alert("ZIP Lib error"); 
                    const zip = new JSZip(); 
                    let count = 0; 
                    segments.forEach((s, i) => { if (s.image.url) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, s.image.url.split(',')[1], { base64: true }); count++; } }); 
                    if (count === 0) return alert("Không có ảnh"); 
                    // Comment: Fix: Cast awaited result of generateAsync to any then to Blob to satisfy createObjectURL type requirements and resolve unknown type error
                    const content = (await zip.generateAsync({ type: "blob" })) as any as Blob; 
                    const link = document.createElement('a'); 
                    link.href = URL.createObjectURL(content); 
                    link.download = `nhan_hoa_2_images.zip`; 
                    link.click(); 
                }} className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-3xl shadow-xl hover:bg-black transition-all uppercase tracking-widest text-base">Tải bộ ảnh (ZIP)</button>
                <button onClick={() => { const text = segments.map(s => s.videoPrompt.text).filter(t => t).join('\n'); const blob = new Blob([text], { type: 'text/plain' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'prompts.txt'; link.click(); }} className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-3xl shadow-xl hover:bg-orange-700 transition-all uppercase tracking-widest text-base">Tải Prompt (TXT)</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Personification2Module;

import React, { useState, useEffect, useRef } from 'react';
import { ScriptParts } from '../types';
import * as service from '../services/reviewDoiThoaiService';
import ScriptSection from '../components/ScriptSection';
import ImageCard, { KOC_POSES, CAMERA_ANGLES, CAMERA_SHOTS } from '../components/ImageCard';

declare var JSZip: any;

const VOICE_OPTIONS = ["Giọng Bắc 20-40 tuổi", "Giọng Nam 20-40 tuổi", "Giọng Bắc 50-60 tuổi", "Giọng Nam 50-60 tuổi", "Giọng Bắc 60-80 tuổi", "Giọng Nam 60-80 tuổi"];
const ADDRESSING_OPTIONS = ["em - anh chị", "tui - mấy bà", "mình - mọi người", "con - cô chú", "con - ba mẹ", "cháu - ông bà", "tao - mày"];
const TONE_OPTIONS = ["Hào hứng", "Chân thành", "Kịch tính", "Hài hước", "Chuyên gia", "Nhẹ nhàng", "Thúc giục"];

const SCENE_COUNT_OPTIONS = Array.from({ length: 13 }, (_, i) => ({ count: i + 3, label: `${i + 3} cảnh - ${(i + 3) * 8}s` }));

const SPEAKER_OPTIONS = [
  { value: 'A', label: 'NHÂN VẬT A' },
  { value: 'B', label: 'NHÂN VẬT B' }
];

const ReviewDoiThoaiModule: React.FC = () => {
  const storageKey = "review_doithoai_v22_final_buttons";
  const [state, setState] = useState<any>({
    charA: { faceFile: null, facePreview: null, outfitFile: null, outfitPreview: null, processedOutfit: null, isExtractingOutfit: false, gender: 'Nữ', voice: VOICE_OPTIONS[0], addressing: 'em - anh chị', description: '' },
    charB: { faceFile: null, facePreview: null, outfitFile: null, outfitPreview: null, processedOutfit: null, isExtractingOutfit: false, gender: 'Nam', voice: VOICE_OPTIONS[1], addressing: 'anh - em', description: '' },
    backgroundFile: null, backgroundPreview: null,
    productFiles: [], productPreviews: [], productName: '', keyword: '',
    sceneCount: 5, backgroundNote: '', imageStyle: 'Realistic', 
    userContent: '', scriptTone: 'Hào hứng',
    isGenerating: false, script: null, images: {}, videoPrompts: {}, sceneChars: {}, sceneSpeakers: {}
  });

  const productInput = useRef<HTMLInputElement>(null);
  const faceAInput = useRef<HTMLInputElement>(null);
  const faceBInput = useRef<HTMLInputElement>(null);
  const outfitAInput = useRef<HTMLInputElement>(null);
  const outfitBInput = useRef<HTMLInputElement>(null);
  const bgInputRef = useRef<HTMLInputElement>(null);
  const localJsonRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) {
      try {
        const p = JSON.parse(saved);
        setState((prev: any) => ({ 
          ...prev, 
          ...p, 
          productFiles: [], 
          charA: { ...p.charA, faceFile: null, outfitFile: null }, 
          charB: { ...p.charB, faceFile: null, outfitFile: null },
          backgroundFile: null
        }));
      } catch (e) {}
    }
  }, []);

  useEffect(() => {
    try {
      const { productFiles, charA, charB, backgroundFile, isGenerating, ...rest } = state;
      const persistentState = {
          ...rest,
          charA: { ...charA, faceFile: null, outfitFile: null },
          charB: { ...charB, faceFile: null, outfitFile: null },
          backgroundFile: null
      };
      localStorage.setItem(storageKey, JSON.stringify(persistentState));
    } catch (e) {}
  }, [state]);

  const processImportData = async (importedData: any) => {
    try {
      if (!Array.isArray(importedData) || importedData.length === 0) return;
      window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 10, complete: false } }));

      const first = importedData[0];
      const inputs = first.inputs || {};
      const settings = inputs.settings || {};

      const newState = {
        ...state,
        productName: inputs.productName || state.productName,
        keyword: inputs.keyword || state.keyword,
        userContent: inputs.userContent || state.userContent,
        backgroundNote: inputs.backgroundNote || state.backgroundNote,
        scriptTone: settings.scriptTone || state.scriptTone,
        sceneCount: importedData.length,
        imageStyle: settings.imageStyle || state.imageStyle,
        charA: { ...state.charA, ...inputs.charA, faceFile: null, outfitFile: null },
        charB: { ...state.charB, ...inputs.charB, faceFile: null, outfitFile: null },
        productPreviews: inputs.productPreviews || [],
        backgroundPreview: inputs.backgroundPreview || state.backgroundPreview,
        script: {}, images: {}, videoPrompts: {}, sceneChars: {}, sceneSpeakers: {}
      };

      for (let i = 0; i < importedData.length; i++) {
        const item = importedData[i];
        const key = `v${i + 1}`;
        const itemInputs = item.inputs || {};
        const itemSettings = itemInputs.settings || {};

        newState.script[key] = item.script || '';
        newState.sceneChars[key] = itemInputs.sceneChar || (i % 2 === 0 ? 'A' : 'B');
        newState.sceneSpeakers[key] = itemInputs.sceneSpeaker || newState.sceneChars[key];
        newState.images[key] = {
          url: item.outputImage || '',
          loading: false,
          pose: itemSettings.pose || '',
          angle: itemSettings.angle || '',
          shot: itemSettings.shot || '',
          customPrompt: itemSettings.customPrompt || ''
        };
        newState.videoPrompts[key] = { 
          text: item.videoPrompt || '', 
          loading: false, 
          visible: !!item.videoPrompt 
        };

        const percent = Math.round(((i + 1) / importedData.length) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === importedData.length - 1 } }));
        await new Promise(r => setTimeout(r, 20));
      }
      setState(newState);
    } catch (e) { alert("Lỗi nạp dữ liệu!"); }
  };

  const constructExportData = () => {
    const keys = state.script ? Object.keys(state.script) : [];
    return keys.map((key, index) => ({
      stt: index + 1,
      inputs: {
        productName: state.productName,
        keyword: state.keyword,
        userContent: state.userContent,
        backgroundNote: state.backgroundNote,
        charA: { gender: state.charA.gender, voice: state.charA.voice, addressing: state.charA.addressing, description: state.charA.description, facePreview: state.charA.facePreview, processedOutfit: state.charA.processedOutfit },
        charB: { gender: state.charB.gender, voice: state.charB.voice, addressing: state.charB.addressing, description: state.charB.description, facePreview: state.charB.facePreview, processedOutfit: state.charB.processedOutfit },
        productPreviews: state.productPreviews,
        backgroundPreview: state.backgroundPreview,
        sceneChar: state.sceneChars[key],
        sceneSpeaker: state.sceneSpeakers[key],
        settings: {
          imageStyle: state.imageStyle,
          scriptTone: state.scriptTone,
          pose: state.images[key]?.pose || '',
          angle: state.images[key]?.angle || '',
          shot: state.images[key]?.shot || '',
          customPrompt: state.images[key]?.customPrompt || ''
        }
      },
      script: state.script[key],
      outputImage: state.images[key]?.url || '',
      videoPrompt: state.videoPrompts[key]?.text || ''
    }));
  };

  const handleLocalExportJson = () => {
    const exportData = constructExportData();
    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Review_DoiThoai_${Date.now()}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  useEffect(() => {
    const handleGlobalExport = () => {
      const data = constructExportData();
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { detail: { data, moduleName: 'Review_Doi_Thoai' } }));
    };
    const handleGlobalImport = (e: any) => processImportData(e.detail);
    window.addEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    };
  }, [state]);

  const handleGenerateScript = async () => {
    if (!state.productName) return alert("Thiếu tên sản phẩm");
    setState(p => ({ ...p, isGenerating: true }));
    try {
      const pParts = state.productFiles.length > 0 
        ? await Promise.all(state.productFiles.map(f => service.fileToGenerativePart(f)))
        : (state.productPreviews || []).map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      const script = await service.generateDoiThoaiScript(pParts, state.productName, state.keyword, state.sceneCount, state.charA, state.charB, state.userContent, state.backgroundNote);
      const sceneChars: any = {};
      const sceneSpeakers: any = {};
      const initialImages: any = {};
      const initialPrompts: any = {};
      Object.keys(script).forEach((k, i) => {
          const defaultChar = (i % 2 === 0) ? 'A' : 'B';
          sceneChars[k] = defaultChar;
          sceneSpeakers[k] = defaultChar;
          initialImages[k] = { url: '', loading: false, pose: '', angle: '', shot: '', customPrompt: '' };
          initialPrompts[k] = { text: '', loading: false, visible: false };
      });
      setState(p => ({ ...p, script, sceneChars, sceneSpeakers, images: initialImages, videoPrompts: initialPrompts, isGenerating: false }));
    } catch (e) { setState(p => ({ ...p, isGenerating: false })); }
  };

  const handleGenImage = async (key: string) => {
    setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], loading: true } } }));
    try {
      const getB64Part = (url: string | null) => (url && url.startsWith('data:')) ? { mimeType: 'image/png', data: url.split(',')[1] } : null;
      const currentImg = state.images[key];
      const url = await service.generateDoiThoaiImage(
        [], getB64Part(state.charA.facePreview), getB64Part(state.charB.facePreview),
        getB64Part(state.charA.processedOutfit || state.charA.outfitPreview),
        getB64Part(state.charB.processedOutfit || state.charB.outfitPreview),
        state.productName, state.script[key], state.imageStyle, state.sceneChars[key],
        state.charA.gender, state.charB.gender, currentImg.pose || '', currentImg.angle || '',
        currentImg.shot || '', currentImg.customPrompt || '', getB64Part(state.backgroundPreview), state.backgroundNote
      );
      setState(p => ({ ...p, images: { ...p.images, [key]: { ...currentImg, url, loading: false } } }));
    } catch (e) { setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], loading: false, error: 'Lỗi' } } })); }
  };

  const handleGenVideoPrompt = async (key: string) => {
    setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: true, visible: true } } }));
    try {
      const speakerTag = state.sceneSpeakers[key];
      const speakerLabel = speakerTag === 'B' ? 'Nhân vật B' : (speakerTag === 'A' ? 'Nhân vật A' : 'Cả hai nhân vật');
      const speakerDescription = speakerTag === 'B' ? state.charB.description : state.charA.description;
      const gender = speakerTag === 'B' ? state.charB.gender : state.charA.gender;
      const voice = speakerTag === 'B' ? state.charB.voice : state.charA.voice;
      const currentImg = state.images[key];
      const prompt = await service.generateDoiThoaiVeoPrompt(
        state.productName, state.script[key], speakerLabel, speakerDescription,
        gender, voice, state.imageStyle, state.scriptTone, currentImg.shot || 'Medium Shot',
        state.backgroundNote, false, currentImg.url, state.productPreviews?.[0]?.split(',')[1]
      );
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (error) { setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } })); }
  };

  const handleBulkAction = async (type: 'image' | 'prompt') => {
    if (!state.script) return;
    for (const key of Object.keys(state.script)) {
      if (type === 'image') await handleGenImage(key); else await handleGenVideoPrompt(key);
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm mb-10">
        <div className="flex justify-between items-center mb-8 border-b pb-4">
           <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Dialogue Review</h2>
           <span className="bg-orange-100 text-orange-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest">PRO 2.6 (Dialogue Lock)</span>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="space-y-4 bg-orange-50/30 p-6 rounded-2xl border border-orange-100">
            <h3 className="text-xs font-black text-orange-600 uppercase tracking-widest px-1">Nhân vật A</h3>
            <div className="grid grid-cols-2 gap-3">
              <div onClick={() => faceAInput.current?.click()} className="aspect-square border-2 border-dashed border-orange-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative">
                {state.charA.facePreview ? <img src={state.charA.facePreview} className="h-full object-cover w-full" /> : <span className="text-[9px] font-bold text-slate-400 uppercase">Mặt A</span>}
                <input type="file" ref={faceAInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charA: { ...p.charA, facePreview: ev.target?.result as string } })); r.readAsDataURL(f); } }} />
              </div>
              <div onClick={() => outfitAInput.current?.click()} className="aspect-square border-2 border-dashed border-orange-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative">
                {state.charA.outfitPreview ? <img src={state.charA.outfitPreview} className="h-full object-cover w-full" /> : <span className="text-[9px] font-bold text-slate-400 uppercase">Đồ A</span>}
                <input type="file" ref={outfitAInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charA: { ...p.charA, outfitPreview: ev.target?.result as string } })); r.readAsDataURL(f); } }} />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <select value={state.charA.gender} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, gender: e.target.value } }))} className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-xs"><option value="Nữ">Nữ</option><option value="Nam">Nam</option></select>
              <select value={state.charA.voice} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, voice: e.target.value } }))} className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-[10px]">{VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}</select>
            </div>
            <input list="doi-thoai-addr-a" value={state.charA.addressing} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, addressing: e.target.value } }))} className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-xs" placeholder="Xưng hô A" />
            <datalist id="doi-thoai-addr-a">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
            <textarea value={state.charA.description} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, description: e.target.value } }))} placeholder="Mô tả ngoại hình A" className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-xs resize-none h-16" />
          </div>

          <div className="space-y-4 bg-blue-50/30 p-6 rounded-2xl border border-blue-100">
            <h3 className="text-xs font-black text-blue-600 uppercase tracking-widest px-1">Nhân vật B</h3>
            <div className="grid grid-cols-2 gap-3">
              <div onClick={() => faceBInput.current?.click()} className="aspect-square border-2 border-dashed border-blue-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative">
                {state.charB.facePreview ? <img src={state.charB.facePreview} className="h-full object-cover w-full" /> : <span className="text-[9px] font-bold text-slate-400 uppercase">Mặt B</span>}
                <input type="file" ref={faceBInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charB: { ...p.charB, facePreview: ev.target?.result as string } })); r.readAsDataURL(f); } }} />
              </div>
              <div onClick={() => outfitBInput.current?.click()} className="aspect-square border-2 border-dashed border-blue-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative">
                {state.charB.outfitPreview ? <img src={state.charB.outfitPreview} className="h-full object-cover w-full" /> : <span className="text-[9px] font-bold text-slate-400 uppercase">Đồ B</span>}
                <input type="file" ref={outfitBInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charB: { ...p.charB, facePreview: ev.target?.result as string } })); r.readAsDataURL(f); } }} />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <select value={state.charB.gender} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, gender: e.target.value } }))} className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-xs"><option value="Nữ">Nữ</option><option value="Nam">Nam</option></select>
              <select value={state.charB.voice} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, voice: e.target.value } }))} className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-[10px]">{VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}</select>
            </div>
            <input list="doi-thoai-addr-b" value={state.charB.addressing} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, addressing: e.target.value } }))} className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-xs" placeholder="Xưng hô B" />
            <datalist id="doi-thoai-addr-b">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
            <textarea value={state.charB.description} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, description: e.target.value } }))} placeholder="Mô tả ngoại hình B" className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-xs resize-none h-16" />
          </div>

          <div className="space-y-4">
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest px-1">Nội dung & Sản phẩm</h3>
            <div className="grid grid-cols-2 gap-3">
              <div onClick={() => productInput.current?.click()} className="aspect-square border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden relative">
                {state.productPreviews?.[0] ? <img src={state.productPreviews[0]} className="h-full object-contain" /> : <span className="text-[9px] font-bold text-slate-400 uppercase">Ảnh SP</span>}
                <input type="file" multiple ref={productInput} className="hidden" onChange={e => { if (!e.target.files) return; const files = Array.from(e.target.files); Promise.all(files.map(f => new Promise((resolve) => { const r = new FileReader(); r.onload = (ev) => resolve(ev.target?.result); r.readAsDataURL(f); }))).then(results => setState(p => ({ ...p, productFiles: files, productPreviews: results }))); }} />
              </div>
              <div onClick={() => bgInputRef.current?.click()} className="aspect-square border-2 border-dashed border-indigo-200 rounded-xl flex items-center justify-center bg-indigo-50/30 cursor-pointer overflow-hidden relative">
                {state.backgroundPreview ? <img src={state.backgroundPreview} className="h-full object-cover" /> : <span className="text-[9px] font-bold text-indigo-400 uppercase">Bối cảnh</span>}
                <input type="file" ref={bgInputRef} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, backgroundPreview: ev.target?.result as string })); r.readAsDataURL(f); } }} />
              </div>
            </div>
            <input type="text" value={state.productName} onChange={e => setState(p => ({ ...p, productName: e.target.value }))} placeholder="Tên sản phẩm..." className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-xs outline-none" />
            <textarea value={state.userContent} onChange={e => setState(p => ({ ...p, userContent: e.target.value }))} placeholder="Ý tưởng kịch bản..." className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl h-24 text-xs font-bold focus:ring-2 focus:ring-orange-100 outline-none resize-none leading-relaxed" />
            <div className="grid grid-cols-2 gap-3">
              <select value={state.scriptTone} onChange={e => setState(p => ({ ...p, scriptTone: e.target.value }))} className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-xs">{TONE_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}</select>
              <select value={state.sceneCount} onChange={e => setState(p => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-orange-600 text-xs">{SCENE_COUNT_OPTIONS.map(o => <option key={o.count} value={o.count}>{o.label}</option>)}</select>
            </div>
            <button onClick={handleGenerateScript} disabled={state.isGenerating} className="w-full py-4 bg-orange-600 text-white font-black rounded-xl shadow-lg uppercase text-xs hover:bg-orange-700 disabled:opacity-50">{state.isGenerating ? "Đang tạo..." : "BẮT ĐẦU TẠO ĐỐI THOẠI"}</button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-12 pb-32">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6">
            {Object.keys(state.script).map((key, idx) => {
              const charInShot = state.sceneChars[key] || 'A';
              const speakerTalking = state.sceneSpeakers[key] || charInShot;
              const imageData = state.images[key] || { url: '', loading: false, pose: '', angle: '', shot: '', customPrompt: '' };
              const promptData = state.videoPrompts[key] || { text: '', loading: false, visible: false };

              return (
                <div key={key} className="space-y-4 animate-fadeIn">
                  <div className={`p-2 rounded-xl text-[9px] font-black uppercase text-center border-b-2 ${charInShot === 'A' ? 'bg-orange-50 text-orange-600 border-orange-200' : charInShot === 'B' ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-slate-50 text-slate-600 border-slate-200'}`}>
                    Nhân vật {charInShot} xuất hiện
                  </div>
                  <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-inner">
                    {['A', 'B', 'Both'].map(c => (
                      <button 
                        key={c} 
                        onClick={() => setState(p => ({ 
                          ...p, 
                          sceneChars: { ...p.sceneChars, [key]: c },
                          sceneSpeakers: { ...p.sceneSpeakers, [key]: c === 'Both' ? (p.sceneSpeakers[key] || 'A') : c }
                        }))} 
                        className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${charInShot === c ? 'bg-white shadow-sm text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        {c === 'Both' ? 'Cả hai' : `Mẫu ${c}`}
                      </button>
                    ))}
                  </div>

                  <ScriptSection title={`Cảnh ${idx + 1}`} content={state.script[key]} color={charInShot === 'A' ? 'border-orange-500' : charInShot === 'B' ? 'border-blue-500' : 'border-slate-300'} onChange={v => setState(p => ({ ...p, script: { ...p.script, [key]: v } }))} />

                  <ImageCard 
                    label={`Cảnh ${idx+1}`} 
                    imageData={imageData} 
                    videoPrompt={promptData} 
                    onRegenerate={() => handleGenImage(key)} 
                    onGeneratePrompt={() => handleGenVideoPrompt(key)} 
                    onTranslate={() => {}} 
                    onDelete={() => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], url: '', loading: false } } }))}
                    pose={imageData.pose} 
                    onPoseChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: val } } }))} 
                    angle={imageData.angle} 
                    onAngleChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], angle: val } } }))} 
                    shot={imageData.shot}
                    onShotChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], shot: val } } }))}
                    speaker={speakerTalking}
                    onSpeakerChange={(val) => setState(p => ({ ...p, sceneSpeakers: { ...p.sceneSpeakers, [key]: val } }))}
                    speakerOptions={SPEAKER_OPTIONS}
                    customPrompt={imageData.customPrompt || ""} 
                    onCustomPromptChange={v => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: v } } }))} 
                  />
                </div>
              );
            })}
          </div>

          <div className="flex flex-col gap-10 py-12 border-t border-slate-200">
            <div className="flex flex-col md:flex-row items-center justify-center gap-4">
              <button onClick={async () => { for (const k of Object.keys(state.script)) await handleGenImage(k); }} className="w-full md:w-auto px-10 py-4 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-xs uppercase tracking-widest">
                VẼ TẤT CẢ ẢNH AI
              </button>
              <button onClick={async () => { for (const k of Object.keys(state.script)) await handleGenVideoPrompt(k); }} className="w-full md:w-auto px-10 py-4 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-xs uppercase tracking-widest">
                VIẾT TẤT CẢ VIDEO PROMPTS
              </button>
            </div>

            <div className="flex flex-col md:flex-row items-center justify-center gap-4 border-t border-slate-100 pt-10">
              <button 
                onClick={() => localJsonRef.current?.click()} 
                className="w-full md:w-auto px-10 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl border border-slate-200 hover:bg-slate-200 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-sm"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
                Tải Data (Import)
              </button>
              <input type="file" ref={localJsonRef} onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (event) => { try { processImportData(JSON.parse(event.target?.result as string)); } catch (err) { alert("File JSON không hợp lệ!"); } }; r.readAsText(f); } e.target.value = ""; }} className="hidden" accept="application/json" />

              <button 
                onClick={handleLocalExportJson} 
                className="w-full md:w-auto px-10 py-4 bg-indigo-600 text-white font-black rounded-2xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-lg shadow-indigo-100"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                Xuất file JSON
              </button>
            </div>

            <div className="flex flex-col md:flex-row items-center justify-center gap-6">
                <button onClick={async () => { 
                    if (typeof JSZip === 'undefined') return alert("ZIP error"); 
                    const zip = new JSZip(); 
                    let count = 0; 
                    Object.keys(state.images).forEach((k, i) => { if (state.images[k].url) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, state.images[k].url.split(',')[1], { base64: true }); count++; } }); 
                    if (count === 0) return alert("Không có ảnh"); 
                    // Comment: Fix: Cast awaited result of generateAsync to any then to Blob to satisfy createObjectURL type requirements and resolve unknown type error
                    const content = (await zip.generateAsync({ type: "blob" })) as any as Blob; 
                    const link = document.createElement('a'); 
                    link.href = URL.createObjectURL(content); 
                    link.download = `review_doithoai_images.zip`; 
                    link.click(); 
                }} className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-3xl shadow-xl hover:bg-black transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-base">Tải bộ ảnh (ZIP)</button>
                <button onClick={() => { const text = Object.keys(state.videoPrompts).map(k => state.videoPrompts[k].text).filter(t => t).join('\n'); if (!text) return alert("Chưa có prompt"); const blob = new Blob([text], { type: 'text/plain' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'prompts_doithoai.txt'; link.click(); }} className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-3xl shadow-xl hover:bg-orange-700 transition-all uppercase tracking-widest text-base">Tải Prompt (TXT)</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ReviewDoiThoaiModule;
